(516,	'rank_math_notifications',	'a:2:{i:0;a:2:{s:7:\"message\";s:132:\"There was an issue scheduling the recurring action required for Analytics; if the problem persists, please contact our support team.\";s:7:\"options\";a:5:{s:2:\"id\";s:37:\"rank_math_action_scheduler_unschedule\";s:7:\"classes\";s:16:\"rank-math-notice\";s:4:\"type\";s:5:\"error\";s:6:\"screen\";s:34:\"rank-math_page_rank-math-analytics\";s:10:\"capability\";s:0:\"\";}}i:1;a:2:{s:7:\"message\";s:839:\"<p>Hey, we noticed you&#039;ve been using <strong>Rank Math SEO</strong> for more than a week now – that&#039;s awesome!<br>We would love to get your feedback! It&#039;s essential for our continued development. Please consider taking a moment to leave a review of your experience on Trustpilot.</p>\n			<p><strong>Bhanu Ahluwalia</strong><br>Co-founder of Rank Math</p>\n			<p>\n				<a href=\"https://www.trustpilot.com/review/www.rankmath.com\" class=\"rank-math-dismiss-review-notice rank-math-review-action rank-math-review-out\" target=\"_blank\" rel=\"noopener noreferrer\"><strong>Yes, you deserve it</strong></a><br>\n				<a href=\"#\" class=\"rank-math-dismiss-review-notice rank-math-maybe-later-action\">No, maybe later</a><br>\n				<a href=\"#\" class=\"rank-math-dismiss-review-notice rank-math-already-reviewed-action\">I already did</a>\n			</p>\";s:7:\"options\";a:5:{s:2:\"id\";s:30:\"rank_math_review_plugin_notice\";s:7:\"classes\";s:16:\"rank-math-notice\";s:4:\"type\";s:4:\"info\";s:6:\"screen\";s:3:\"any\";s:10:\"capability\";s:15:\"install_plugins\";}}}',	'auto'),
